// Prevención con Redis SETNX (mutex)
public Product getWithLock(String productId) {
  String cached = redis.get("product:" + productId);
  if (cached != null) return deserialize(cached);
  boolean locked = redis.setIfAbsent(
      "lock:" + productId, "1", 5, SECONDS);
  if (locked) {
    Product p = db.findById(productId);
    redis.set("product:" + productId, serialize(p), 5, MINUTES);
    redis.delete("lock:" + productId);
    return p;
  }
  Thread.sleep(100);
  return getWithLock(productId); // reintenta
}

